INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Мирный житель — днём голосует, ночью спит. Главная задача — вычислить мафию по поведению.', NULL, 2, json_object('role', 'Мирный житель', 'side', 'мирные'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Доктор — ночью спасает одного игрока от убийства. Себя лечить можно один раз за игру.', NULL, 3, json_object('role', 'Доктор', 'side', 'мирные'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Шериф (Комиссар) — ночью проверяет одного игрока на принадлежность к мафии.', NULL, 3, json_object('role', 'Шериф', 'side', 'мирные'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Любовница — ночью выбирает игрока, к которому идёт. Если в него стреляет мафия — оба выживают, но она молчит до утра.', NULL, 3, json_object('role', 'Любовница', 'side', 'мирные'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Журналист — ночью сравнивает двух игроков: одна ли у них команда. Узнаёт только факт совпадения.', NULL, 3, json_object('role', 'Журналист', 'side', 'мирные'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Адвокат — раз за игру может на дневном голосовании отменить казнь выбранного игрока.', NULL, 3, json_object('role', 'Адвокат', 'side', 'мирные'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Священник — ночью благословляет игрока: тот не сможет быть убит мафией следующей ночью, но и сам не действует.', NULL, 3, json_object('role', 'Священник', 'side', 'мирные'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Снайпер — мирный с двумя пулями за игру. Ночью может застрелить любого, кроме себя. После выстрела роль раскрывается.', NULL, 3, json_object('role', 'Снайпер-маньяк (нейтрал к мафии)', 'side', 'мирные'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Старушка — ночью узнаёт, сколько мафиози ходило к выбранному игроку. Сама беззащитна.', NULL, 2, json_object('role', 'Старушка-сплетница', 'side', 'мирные'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Бомж — ночью ночует у выбранного игрока. Если в хозяина стреляли — погибает вместе с ним и узнаёт убийцу (если выжил, делится утром).', NULL, 2, json_object('role', 'Бомж', 'side', 'мирные'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Мафия — ночью вместе с подельниками выбирает жертву. Днём притворяется мирным.', NULL, 3, json_object('role', 'Мафия', 'side', 'мафия'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Дон — глава мафии. Ночью проверяет, не Шериф ли выбранный игрок. Голос Дона решает спор внутри мафии.', NULL, 3, json_object('role', 'Дон', 'side', 'мафия'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Кардинал (Крёстный отец) — для проверки Шерифа выглядит мирным. Голосует вместе с мафией.', NULL, 3, json_object('role', 'Кардинал', 'side', 'мафия'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Подельник — рядовой член мафии без особых способностей, помогает выбирать жертву.', NULL, 2, json_object('role', 'Подельник', 'side', 'мафия'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Манипулятор — раз за игру может на дневном голосовании украсть один голос у любого игрока.', NULL, 3, json_object('role', 'Манипулятор', 'side', 'мафия'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Оборотень — мафиози, который для проверки выглядит как мирный. Активируется, если погиб Дон.', NULL, 3, json_object('role', 'Оборотень', 'side', 'мафия'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Якудза — раз за игру может вместо обычного убийства устроить «двойное»: погибают двое выбранных.', NULL, 3, json_object('role', 'Якудза', 'side', 'мафия'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Чёрная вдова — ночью соблазняет игрока: тот не может пользоваться своей ночной способностью.', NULL, 3, json_object('role', 'Чёрная вдова', 'side', 'мафия'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Маньяк — играет сам за себя, ночью убивает одного игрока. Побеждает, если остался один на один с любым другим.', NULL, 3, json_object('role', 'Маньяк', 'side', 'нейтрал'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Самоубийца — побеждает, если его казнят дневным голосованием. До этого ведёт себя максимально подозрительно.', NULL, 3, json_object('role', 'Самоубийца', 'side', 'нейтрал'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Шут — побеждает, если его повесят на дневном голосовании, ошибочно приняв за мафию.', NULL, 3, json_object('role', 'Шут', 'side', 'нейтрал'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Бессмертный — раз за игру переживает убийство или казнь. После — становится обычным мирным.', NULL, 3, json_object('role', 'Бессмертный', 'side', 'нейтрал'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Вампир — ночью кусает игрока, превращая его в вампира. Побеждает, когда вампиров становится больше, чем не-вампиров.', NULL, 3, json_object('role', 'Вампир', 'side', 'нейтрал'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Призрак — погибает первой ночью, но продолжает играть: раз за игру передаёт живому одно слово через ведущего.', NULL, 2, json_object('role', 'Призрак', 'side', 'нейтрал'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Роль', 'Влюблённый — ночью выбирает пару. Если один из них умирает, второй умирает следом от горя.', NULL, 3, json_object('role', 'Влюблённый', 'side', 'нейтрал'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Случилось убийство в библиотеке. Чьё тело нашли и какая улика рядом?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Мафия оставила записку на месте преступления. Что в ней?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Утром в городе пропали все собаки. Кто-то заметил подозрительного игрока — кого?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'В баре нашли мёртвого бармена. Опишите, как именно его убили.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Город охватила паника: распространился слух о двойнике мафиози. Расскажите слух.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'На рассвете в парке нашли странный символ. Каждый игрок предполагает, что он означает.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Свидетель видел силуэт в ночи. Опишите силуэт так, чтобы он подходил двум игрокам.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Кто-то поджёг старую мельницу. Каждый игрок объясняет, где был ночью.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'В реке всплыло тело без документов. Игроки по очереди называют, кем мог быть погибший.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Городские часы остановились на 3:17. Что произошло именно в этот момент?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Мафия похитила почтальона. Какое письмо он не успел доставить?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'В кафе подсыпали что-то в кофе. Кто пил первым и что почувствовал?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'На рынке торговка раскричалась: «Я всё видела!». Через минуту её не стало. Что она видела?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Жертву нашли с цветком в руке. Каждый игрок объясняет значение цветка.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Кто-то сжёг архив полиции. Какие документы исчезли?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Утром на главной площади появилось пугало с лицом одного из жителей. Чьё?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Свадьба отменена: жених не пришёл. Где он провёл ночь по версии каждого игрока?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'В церкви исчезла икона. Каждый игрок по очереди объясняет, как это связано с мафией.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Школьный учитель пропал перед экзаменами. Чьи родители больше всего рады?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Кто-то расклеил по городу анонимные плакаты с цитатами. Прочитайте по одной фразе.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'В подвале нашли тайник с деньгами. Кому они принадлежат и почему?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'На дереве у площади вырезано имя. Каждый игрок предлагает имя одного игрока и причину.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Кто-то отравил городской фонтан. Симптомы — слухи и паранойя. Опишите свою паранойю.', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Мафиози забыл на месте преступления свою вещь. Каждый игрок описывает «улику».', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'В город приехал детектив из столицы. Кому из игроков он первым задаст вопрос и какой?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
INSERT INTO cards (game_id, type, text, vibes, intensity, meta, source, approved, created_at) VALUES ('mafia', 'Сценарий', 'Ночью лаяла собака под окнами одного из жителей. Чьего?', NULL, 2, json_object('kind','scenario'), 'admin', 1, strftime('%s','now')*1000);
